import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
import os

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Securely retrieve environment variables
    connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
    if not connection_string:
        return func.HttpResponse("Storage connection string not configured.", status_code=500)

    blob_path = req.params.get('blob_path')
    if not blob_path:
        return func.HttpResponse("Please pass a blob_path on the query string.", status_code=400)

    try:
        # Initialize the BlobServiceClient
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Extract container name and blob name from the blob path
        path_parts = blob_path.split('/', 1)
        if len(path_parts) != 2:
            return func.HttpResponse("Invalid blob path format. Expected format: 'container/blob'.", status_code=400)
        
        container_name, blob_name = path_parts

        # Get the blob client
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)

        # Download the blob content
        blob_data = blob_client.download_blob().readall()

        # Return the blob content as response
        return func.HttpResponse(blob_data, status_code=200, mimetype='application/octet-stream')

    except Exception as e:
        logging.error(f"Error accessing blob: {e}")
        return func.HttpResponse("Error accessing blob.", status_code=500)